36	// ParseSince converts a CLI/query window string into a cutoff time.
37	// Empty input returns the zero time and no error.
38	func ParseSince(raw string) (time.Time, error) {
39		raw = strings.TrimSpace(raw)
40		if raw == "" {
41			return time.Time{}, nil
42		}
43	
44		now := time.Now()
45		switch raw {
46		case "today":
47			return time.Date(now.Year(), now.Month(), now.Day(), 0, 0, 0, 0, now.Location()), nil
48		case "now":
49			return now, nil
50		}
51	
52		if strings.HasSuffix(raw, "d") {
53			n, err := parsePositiveInt(strings.TrimSuffix(raw, "d"))
54			if err != nil {
55				return time.Time{}, fmt.Errorf("expected Nd window, got %q", raw)
56			}
57			return now.AddDate(0, 0, -n), nil
58		}
59	
60		for _, layout := range []string{time.RFC3339, "2006-01-02"} {
61			if parsed, err := time.Parse(layout, raw); err == nil {
62				return parsed, nil
63			}
64		}
65	
66		return time.Time{}, fmt.Errorf("unrecognized window %q, want today, Nd, RFC3339, or YYYY-MM-DD", raw)
67	}
