265	func (s *Service) Summary(query Query) (AggregateSummary, error) {
266		beads, sessions, _, sessionCostPresent, err := s.loadInputs()
267		if err != nil {
268			return AggregateSummary{}, err
269		}
270	
271		costReport, err := s.Cost(query)
272		if err != nil {
273			return AggregateSummary{}, err
274		}
275		cycleReport, err := s.CycleTime(query)
276		if err != nil {
277			return AggregateSummary{}, err
278		}
279		reworkReport, err := s.Rework(query)
280		if err != nil {
281			return AggregateSummary{}, err
282		}
283	
284		var summary AggregateSummary
285		visibleBeads, visibleBeadIDs := beadsVisibleInSummaryWindow(beads, query, costReport, cycleReport, reworkReport)
286		summary.Beads.Total = len(visibleBeads)
287	
288		for _, b := range visibleBeads {
289			switch b.Status {
290			case bead.StatusOpen:
291				summary.Beads.Open++
292			case bead.StatusInProgress:
293				summary.Beads.InProgress++
294			case bead.StatusClosed:
295				summary.Beads.Closed++
296			}
297		}
298		var cycleKnownTotalMS int64
299		for _, row := range cycleReport.Beads {
300			if query.HasSince {
301				if _, ok := visibleBeadIDs[row.BeadID]; !ok {
302					continue
303				}
304			}
305			if row.CycleState == stateKnown {
306				summary.Beads.KnownCycleTime++
307				summary.CycleTime.KnownCount++
308				if row.CycleTimeMS != nil {
309					cycleKnownTotalMS += *row.CycleTimeMS
310					if summary.CycleTime.MinMS == nil || *row.CycleTimeMS < *summary.CycleTime.MinMS {
311						summary.CycleTime.MinMS = int64Ptr(*row.CycleTimeMS)
312					}
313					if summary.CycleTime.MaxMS == nil || *row.CycleTimeMS > *summary.CycleTime.MaxMS {
314						summary.CycleTime.MaxMS = int64Ptr(*row.CycleTimeMS)
315					}
316				}
317			} else {
318				summary.Beads.UnknownCycleTime++
319				summary.CycleTime.UnknownCount++
320			}
321		}
322		if summary.CycleTime.KnownCount > 0 {
323			avg := cycleKnownTotalMS / int64(summary.CycleTime.KnownCount)
324			summary.CycleTime.AverageMS = &avg
325		}
326	
327		costBeadCount := 0
328		featureIDs := make(map[string]struct{})
329		for _, row := range costReport.Beads {
330			if query.HasSince {
331				if _, ok := visibleBeadIDs[row.BeadID]; !ok && len(row.SessionIDs) == 0 {
332					continue
333				}
334			}
335			costBeadCount++
336			if row.SpecID != "" {
337				featureIDs[row.SpecID] = struct{}{}
338			}
339			switch row.CostState {
340			case stateKnown:
341				summary.Beads.KnownCost++
342			case stateEstimated:
343				summary.Beads.EstimatedCost++
344			default:
345				summary.Beads.UnknownCost++
346			}
347		}
348	
349		summary.Cost.Beads = costBeadCount
350		summary.Cost.Features = len(featureIDs)
351		for _, row := range costReport.Beads {
352			if query.HasSince {
353				if _, ok := visibleBeadIDs[row.BeadID]; !ok && len(row.SessionIDs) == 0 {
354					continue
355				}
356			}
357			switch row.CostState {
358			case stateKnown:
359				if row.CostUSD != nil {
360					summary.Cost.KnownCostUSD += *row.CostUSD
361				}
362			case stateEstimated:
363				if row.CostUSD != nil {
364					summary.Cost.EstimatedCostUSD += *row.CostUSD
365				}
366			default:
367				summary.Cost.UnknownBeads++
368			}
369		}
370	
371		for _, sess := range sessions {
372			if query.HasSince && sess.Timestamp.Before(query.Since) {
373				continue
374			}
375			summary.Sessions.Total++
376			summary.Sessions.InputTokens += sessionInputTokens(sess)
377			summary.Sessions.OutputTokens += sessionOutputTokens(sess)
378			summary.Sessions.TotalTokens += sessionTotalTokens(sess)
379			if sessionBeadID(sess) != "" {
380				summary.Sessions.Correlated++
381			} else {
382				summary.Sessions.Uncorrelated++
383			}
384			switch sessionCostState(sess, sessionCostPresent[sess.ID]) {
385			case stateKnown:
386				summary.Sessions.KnownCost++
387			case stateEstimated:
388				summary.Sessions.EstimatedCost++
389			default:
390				summary.Sessions.UnknownCost++
391			}
392			if cost := sessionDerivedCost(sess, sessionCostPresent[sess.ID]); cost != nil {
393				summary.Sessions.CostUSD += *cost
394			}
395		}
396	
397		for _, row := range reworkReport.Beads {
398			if query.HasSince {
399				if _, ok := visibleBeadIDs[row.BeadID]; !ok {
400					continue
401				}
402			}
403			if row.ReworkState != stateKnown {
404				summary.Rework.UnknownCount++
405				continue
406			}
407			summary.Rework.KnownClosed++
408			if row.Reopened {
409				summary.Rework.KnownReopened++
410				summary.Beads.Reopened++
411			}
412			if row.RevisionCount != nil {
413				summary.Rework.RevisionCount += *row.RevisionCount
414			}
415		}
416		if summary.Rework.KnownClosed > 0 {
417			summary.Rework.ReopenRate = float64(summary.Rework.KnownReopened) / float64(summary.Rework.KnownClosed)
418		}
419		return summary, nil
420	}
