422	// Cost computes bead and feature cost attribution.
423	func (s *Service) Cost(query Query) (CostReport, error) {
424		beads, sessions, sessionByID, sessionCostPresent, err := s.loadInputs()
425		if err != nil {
426			return CostReport{}, err
427		}
428		_ = sessions
429	
430		selected := selectBeads(beads, query.BeadID, query.FeatureID)
431		rows := make([]BeadCostRow, 0, len(selected))
432		for _, b := range selected {
433			row := buildBeadCostRow(b, sessions, sessionByID, sessionCostPresent, query)
434			rows = append(rows, row)
435		}
436		sort.Slice(rows, func(i, j int) bool {
437			return rows[i].BeadID < rows[j].BeadID
438		})
439	
440		featureRows := buildFeatureCostRows(rows)
441	
442		report := CostReport{
443			Scope:     costScope(query),
444			Window:    windowForQuery(query),
445			BeadID:    query.BeadID,
446			FeatureID: query.FeatureID,
447			Beads:     rows,
448			Features:  featureRows,
449		}
450	
451		for _, row := range rows {
452			report.Summary.Beads++
453			switch row.CostState {
454			case stateKnown:
455				if row.CostUSD != nil {
456					report.Summary.KnownCostUSD += *row.CostUSD
457				}
458			case stateEstimated:
459				if row.CostUSD != nil {
460					report.Summary.EstimatedCostUSD += *row.CostUSD
461				}
462			default:
463				report.Summary.UnknownBeads++
464			}
465		}
466		report.Summary.Features = len(featureRows)
467		return report, nil
468	}
