470	// CycleTime computes lifecycle timing facts.
471	func (s *Service) CycleTime(query Query) (CycleTimeReport, error) {
472		beads, sessions, sessionByID, _, err := s.loadInputs()
473		if err != nil {
474			return CycleTimeReport{}, err
475		}
476		_ = sessions
477	
478		rows := make([]CycleTimeRow, 0, len(beads))
479		for _, b := range beads {
480			row := buildCycleTimeRow(s.WorkingDir, b, sessionByID)
481			if query.HasSince && row.FirstClosedAt != nil && row.FirstClosedAt.Before(query.Since) {
482				continue
483			}
484			rows = append(rows, row)
485		}
486		sort.Slice(rows, func(i, j int) bool {
487			if rows[i].FirstClosedAt == nil && rows[j].FirstClosedAt == nil {
488				return rows[i].BeadID < rows[j].BeadID
489			}
490			if rows[i].FirstClosedAt == nil {
491				return false
492			}
493			if rows[j].FirstClosedAt == nil {
494				return true
495			}
496			if !rows[i].FirstClosedAt.Equal(*rows[j].FirstClosedAt) {
497				return rows[i].FirstClosedAt.Before(*rows[j].FirstClosedAt)
498			}
499			return rows[i].BeadID < rows[j].BeadID
500		})
501	
502		report := CycleTimeReport{
503			Scope:  "all",
504			Window: windowForQuery(query),
505			Beads:  rows,
506		}
507		for _, row := range rows {
508			if row.CycleState == stateKnown && row.CycleTimeMS != nil {
509				report.Summary.KnownCount++
510				if report.Summary.AverageMS == nil {
511					report.Summary.AverageMS = int64Ptr(0)
512					report.Summary.MinMS = int64Ptr(*row.CycleTimeMS)
513					report.Summary.MaxMS = int64Ptr(*row.CycleTimeMS)
514				}
515				*report.Summary.AverageMS += *row.CycleTimeMS
516				if row.CycleTimeMS != nil {
517					if *row.CycleTimeMS < *report.Summary.MinMS {
518						*report.Summary.MinMS = *row.CycleTimeMS
519					}
520					if *row.CycleTimeMS > *report.Summary.MaxMS {
521						*report.Summary.MaxMS = *row.CycleTimeMS
522					}
523				}
524			} else {
525				report.Summary.UnknownCount++
526			}
527		}
528		if report.Summary.KnownCount > 0 && report.Summary.AverageMS != nil {
529			avg := *report.Summary.AverageMS / int64(report.Summary.KnownCount)
530			report.Summary.AverageMS = &avg
531		}
532		return report, nil
533	}
