551		sort.Slice(rows, func(i, j int) bool {
552			if rows[i].FirstClosedAt == nil && rows[j].FirstClosedAt == nil {
553				return rows[i].BeadID < rows[j].BeadID
554			}
555			if rows[i].FirstClosedAt == nil {
