592	func costScope(query Query) string {
593		switch {
594		case query.BeadID != "":
595			return "bead"
596		case query.FeatureID != "":
597			return "feature"
598		default:
599			return "all"
600		}
601	}
602	
603	func windowForQuery(query Query) Window {
604		if !query.HasSince || query.Since.IsZero() {
605			return Window{}
606		}
607		since := query.Since.UTC()
608		return Window{
609			Since: &since,
610			Label: since.Format(time.RFC3339),
611		}
612	}
613	
614	func beadsVisibleInSummaryWindow(beads []bead.Bead, query Query, costReport CostReport, cycleReport CycleTimeReport, reworkReport ReworkReport) ([]bead.Bead, map[string]struct{}) {
615		if !query.HasSince || query.Since.IsZero() {
616			visibleIDs := make(map[string]struct{}, len(beads))
617			for _, b := range beads {
618				visibleIDs[b.ID] = struct{}{}
619			}
620			return beads, visibleIDs
621		}
622	
623		visibleIDs := make(map[string]struct{}, len(beads))
624		for _, row := range costReport.Beads {
625			if len(row.SessionIDs) > 0 {
626				visibleIDs[row.BeadID] = struct{}{}
627			}
628		}
629		for _, row := range cycleReport.Beads {
630			if row.FirstClosedAt != nil {
631				visibleIDs[row.BeadID] = struct{}{}
632			}
633		}
634		for _, row := range reworkReport.Beads {
635			if row.FirstClosedAt != nil {
636				visibleIDs[row.BeadID] = struct{}{}
637			}
638		}
639	
640		visible := make([]bead.Bead, 0, len(beads))
641		for _, b := range beads {
642			if _, ok := visibleIDs[b.ID]; !ok {
643				continue
644			}
645			visible = append(visible, b)
646		}
647		return visible, visibleIDs
648	}
