697	func readSessions(path string) ([]agent.SessionEntry, map[string]bool, error) {
698		if filepath.Base(path) == "sessions.jsonl" {
699			logDir := filepath.Dir(path)
700			indexEntries, err := agent.ReadSessionIndex(logDir, agent.SessionIndexQuery{})
701			if err != nil {
702				return nil, nil, err
703			}
704			sessions := make([]agent.SessionEntry, 0, len(indexEntries))
705			costPresent := make(map[string]bool, len(indexEntries))
706			for _, idx := range indexEntries {
707				entry := agent.SessionIndexEntryToLegacy(idx)
708				sessions = append(sessions, entry)
709				costPresent[entry.ID] = idx.CostPresent || idx.CostUSD != 0
710			}
711			return sessions, costPresent, nil
712		}
713		records, err := readJSONLRecords[sessionLoadRecord](path)
714		if err != nil {
715			return nil, nil, err
716		}
717	
718		sessions := make([]agent.SessionEntry, 0, len(records))
719		costPresent := make(map[string]bool, len(records))
720		for _, rec := range records {
721			sessions = append(sessions, rec.Entry)
722			costPresent[rec.Entry.ID] = rec.CostUSDPresent
723		}
724		return sessions, costPresent, nil
725	}
