727	func readJSONLRecords[T any](path string) ([]T, error) {
728		f, err := os.Open(path)
729		if os.IsNotExist(err) {
730			return nil, nil
731		}
732		if err != nil {
733			return nil, err
734		}
735		defer f.Close()
736	
737		scanner := bufio.NewScanner(f)
738		// 16MB max line — matches bead/session scanners; process-metrics rows are
739		// small but consistency avoids surprise truncation if a writer ever grows.
740		scanner.Buffer(make([]byte, 0, 64*1024), 16*1024*1024)
741		var out []T
742		for scanner.Scan() {
743			line := strings.TrimSpace(scanner.Text())
744			if line == "" {
745				continue
746			}
747			var rec T
748			if err := json.Unmarshal([]byte(line), &rec); err != nil {
749				continue
750			}
751			out = append(out, rec)
752		}
753		if err := scanner.Err(); err != nil {
754			return nil, err
755		}
756		return out, nil
757	}
