780	func buildBeadCostRow(b bead.Bead, sessions []agent.SessionEntry, sessionByID map[string]agent.SessionEntry, sessionCostPresent map[string]bool, query Query) BeadCostRow {
781		matches := matchedSessionsForBead(b, sessions, sessionByID)
782		if query.HasSince {
783			filtered := matches[:0]
784			for _, sess := range matches {
785				if sess.Timestamp.Before(query.Since) {
786					continue
787				}
788				filtered = append(filtered, sess)
789			}
790			matches = filtered
791		}
792	
793		row := BeadCostRow{
794			BeadID:     b.ID,
795			Title:      b.Title,
796			SpecID:     extraString(b, "spec-id", "spec_id"),
797			Status:     b.Status,
798			SessionIDs: make([]string, 0, len(matches)),
799			Provenance: make([]SourceRef, 0, len(matches)),
800		}
801	
802		var costTotal float64
803		var knownCount, estimatedCount, unknownCount int
804		for _, sess := range matches {
805			explicitCost := sessionCostPresent[sess.ID]
806			row.SessionIDs = append(row.SessionIDs, sess.ID)
807			row.InputTokens += sessionInputTokens(sess)
808			row.OutputTokens += sessionOutputTokens(sess)
809			row.TotalTokens += sessionTotalTokens(sess)
810	
811			if cost := sessionDerivedCost(sess, explicitCost); cost != nil {
812				costTotal += *cost
813				if sessionCostState(sess, explicitCost) == stateKnown {
814					knownCount++
815				} else {
816					estimatedCount++
817				}
818			} else {
819				unknownCount++
820			}
821	
822			row.Provenance = append(row.Provenance, sourceRefForSession(b.ID, sess))
823		}
824	
825		switch {
826		case len(matches) == 0:
827			row.CostState = stateUnknown
828		case unknownCount > 0 && knownCount == 0 && estimatedCount == 0:
829			row.CostState = stateUnknown
830		case estimatedCount > 0:
831			row.CostState = stateEstimated
832		default:
833			row.CostState = stateKnown
834		}
835		if row.CostState != stateUnknown {
836			row.CostUSD = float64Ptr(costTotal)
837		}
838		row.UnknownSessions = unknownCount
839		return row
840	}
