842	func buildFeatureCostRows(beadRows []BeadCostRow) []FeatureCostRow {
843		grouped := make(map[string]*FeatureCostRow)
844		for _, row := range beadRows {
845			if row.SpecID == "" {
846				continue
847			}
848			entry, ok := grouped[row.SpecID]
849			if !ok {
850				entry = &FeatureCostRow{SpecID: row.SpecID}
851				grouped[row.SpecID] = entry
852			}
853			entry.BeadIDs = append(entry.BeadIDs, row.BeadID)
854			entry.InputTokens += row.InputTokens
855			entry.OutputTokens += row.OutputTokens
856			entry.TotalTokens += row.TotalTokens
857			if row.CostState == stateUnknown || row.CostUSD == nil {
858				entry.UnknownBeads++
859				continue
860			}
861			switch row.CostState {
862			case stateKnown:
863				if entry.CostUSD == nil {
864					entry.CostUSD = float64Ptr(0)
865				}
866			case stateEstimated:
867				if entry.CostState == stateKnown {
868					entry.CostState = stateEstimated
869				}
870			}
871			if entry.CostUSD == nil {
872				entry.CostUSD = float64Ptr(0)
873			}
874			*entry.CostUSD += *row.CostUSD
875			if row.CostState == stateEstimated {
876				entry.CostState = stateEstimated
877			} else if entry.CostState == "" {
878				entry.CostState = stateKnown
879			}
880		}
881	
882		out := make([]FeatureCostRow, 0, len(grouped))
883		for _, row := range grouped {
884			sort.Strings(row.BeadIDs)
885			if row.CostUSD != nil {
886				if row.CostState == "" {
887					row.CostState = stateKnown
888				}
889			} else {
890				row.CostState = stateUnknown
891			}
892			out = append(out, *row)
893		}
894		sort.Slice(out, func(i, j int) bool {
895			return out[i].SpecID < out[j].SpecID
896		})
897		return out
898	}
