900	func buildCycleTimeRow(workingDir string, b bead.Bead, sessionByID map[string]agent.SessionEntry) CycleTimeRow {
901		row := CycleTimeRow{
902			BeadID:     b.ID,
903			Title:      b.Title,
904			SpecID:     extraString(b, "spec-id", "spec_id"),
905			Status:     b.Status,
906			CreatedAt:  b.CreatedAt.UTC(),
907			CycleState: stateUnknown,
908		}
909	
910		events := beadEvents(b)
911		transitions := recognizedTransitions(events)
912		sort.Slice(transitions, func(i, j int) bool {
913			return transitions[i].At.Before(transitions[j].At)
914		})
915	
916		closeAt, provenance := firstCloseEvidence(workingDir, b, transitions, sessionByID)
917		if closeAt != nil {
918			row.FirstClosedAt = closeAt
919			row.CycleTimeMS = int64Ptr(closeAt.Sub(b.CreatedAt).Milliseconds())
920			row.CycleState = stateKnown
921			row.Provenance = append(row.Provenance, provenance...)
922		}
923	
924		if len(transitions) == 0 {
925			return row
926		}
927	
928		row.Provenance = append(row.Provenance, provenanceForEvents(b.ID, events)...)
929	
930		var lastStatus string
931		var lastAt time.Time
932		var firstClosedSeen bool
933		var reopenCount int
934		var revisionCount int
935		var openMS, inProgressMS, closedMS int64
936		for i, tr := range transitions {
937			if i == 0 {
938				lastStatus = bead.StatusOpen
939				lastAt = b.CreatedAt.UTC()
940			}
941			if tr.At.Before(lastAt) {
942				continue
943			}
944			delta := tr.At.Sub(lastAt).Milliseconds()
945			switch lastStatus {
946			case bead.StatusOpen:
947				openMS += delta
948			case bead.StatusInProgress:
949				inProgressMS += delta
950			case bead.StatusClosed:
951				closedMS += delta
952			}
953			if tr.Status == bead.StatusClosed && !firstClosedSeen {
954				firstClosedSeen = true
955				if row.FirstClosedAt == nil {
956					ts := tr.At
957					row.FirstClosedAt = &ts
958					row.CycleTimeMS = int64Ptr(ts.Sub(b.CreatedAt).Milliseconds())
959					row.CycleState = stateKnown
960				}
961			}
962			if firstClosedSeen {
963				if tr.Status == bead.StatusClosed {
964					// Status closed is part of the close window; do not count it as rework.
965				} else {
966					revisionCount++
967					if lastStatus == bead.StatusClosed && (tr.Status == bead.StatusOpen || tr.Status == bead.StatusInProgress) {
968						reopenCount++
969					}
970				}
971			}
972			lastStatus = tr.Status
973			lastAt = tr.At
974		}
975	
976		end := b.UpdatedAt.UTC()
977		if end.Before(lastAt) {
978			end = lastAt
979		}
980		if !end.IsZero() {
981			delta := end.Sub(lastAt).Milliseconds()
982			switch lastStatus {
983			case bead.StatusOpen:
984				openMS += delta
985			case bead.StatusInProgress:
986				inProgressMS += delta
987			case bead.StatusClosed:
988				closedMS += delta
989			}
990		}
991	
992		if openMS > 0 {
993			row.TimeInOpenMS = int64Ptr(openMS)
994		}
995		if inProgressMS > 0 {
996			row.TimeInProgressMS = int64Ptr(inProgressMS)
997		}
998		if closedMS > 0 {
999			row.TimeInClosedMS = int64Ptr(closedMS)
1000		}
1001		if firstClosedSeen {
1002			row.ReopenCount = intPtr(reopenCount)
1003			row.RevisionCount = intPtr(revisionCount)
1004		}
1005	
1006		if firstClosedSeen {
1007			lastClose := row.FirstClosedAt
1008			for _, tr := range transitions {
1009				if tr.Status == bead.StatusClosed {
1010					ts := tr.At
1011					lastClose = &ts
1012				}
1013			}
1014			row.LastClosedAt = lastClose
1015		}
1016		return row
1017	}
