1019	func buildReworkRow(workingDir string, b bead.Bead, sessionByID map[string]agent.SessionEntry) ReworkRow {
1020		row := ReworkRow{
1021			BeadID: b.ID,
1022			Title:  b.Title,
1023			SpecID: extraString(b, "spec-id", "spec_id"),
1024			Status: b.Status,
1025		}
1026	
1027		events := beadEvents(b)
1028		transitions := recognizedTransitions(events)
1029		sort.Slice(transitions, func(i, j int) bool {
1030			return transitions[i].At.Before(transitions[j].At)
1031		})
1032	
1033		closeAt, provenance := firstCloseEvidence(workingDir, b, transitions, sessionByID)
1034		if closeAt == nil {
1035			return row
1036		}
1037		row.FirstClosedAt = closeAt
1038		row.Provenance = append(row.Provenance, provenance...)
1039		if len(transitions) == 0 {
1040			return row
1041		}
1042		row.ReworkState = stateKnown
1043	
1044		var reopenCount int
1045		var revisionCount int
1046		var sawClose bool
1047		for _, tr := range transitions {
1048			if tr.At.Before(*closeAt) {
1049				continue
1050			}
1051			if tr.Status == bead.StatusClosed {
1052				sawClose = true
1053				continue
1054			}
1055			if sawClose && (tr.Status == bead.StatusOpen || tr.Status == bead.StatusInProgress) {
1056				reopenCount++
1057			}
1058			if tr.Status != bead.StatusClosed {
1059				revisionCount++
1060			}
1061		}
1062		row.Reopened = reopenCount > 0
1063		row.ReopenCount = intPtr(reopenCount)
1064		row.RevisionCount = intPtr(revisionCount)
1065		return row
1066	}
