1068	func matchedSessionsForBead(b bead.Bead, sessions []agent.SessionEntry, sessionByID map[string]agent.SessionEntry) []agent.SessionEntry {
1069		beadID := b.ID
1070		seen := make(map[string]struct{})
1071		out := make([]agent.SessionEntry, 0)
1072	
1073		for _, sess := range sessions {
1074			if sessionBeadID(sess) == beadID {
1075				if _, ok := seen[sess.ID]; !ok {
1076					out = append(out, sess)
1077					seen[sess.ID] = struct{}{}
1078				}
1079			}
1080		}
1081	
1082		if sessionID := extraString(b, "session_id", "session-id"); sessionID != "" {
1083			if sess, ok := sessionByID[sessionID]; ok {
1084				if _, exists := seen[sess.ID]; !exists {
1085					out = append(out, sess)
1086					seen[sess.ID] = struct{}{}
1087				}
1088			}
1089		}
1090	
1091		sort.Slice(out, func(i, j int) bool {
1092			if out[i].Timestamp.Equal(out[j].Timestamp) {
1093				return out[i].ID < out[j].ID
1094			}
1095			return out[i].Timestamp.Before(out[j].Timestamp)
1096		})
1097		return out
1098	}
