1117	func firstCloseEvidence(workingDir string, b bead.Bead, transitions []statusTransition, sessionByID map[string]agent.SessionEntry) (*time.Time, []SourceRef) {
1118		var eventCloseTimes []time.Time
1119		var eventProvenance []SourceRef
1120		for _, tr := range transitions {
1121			if tr.Status != bead.StatusClosed {
1122				continue
1123			}
1124			ts := tr.At
1125			eventCloseTimes = append(eventCloseTimes, ts)
1126			eventProvenance = append(eventProvenance, SourceRef{
1127				BeadID:    b.ID,
1128				Timestamp: &ts,
1129				Source:    "event",
1130			})
1131		}
1132		if len(eventCloseTimes) > 0 {
1133			sort.Slice(eventCloseTimes, func(i, j int) bool { return eventCloseTimes[i].Before(eventCloseTimes[j]) })
1134			first := eventCloseTimes[0]
1135			return &first, eventProvenance
1136		}
1137	
1138		if sha := extraString(b, "closing_commit_sha"); sha != "" {
1139			if ts, ok := commitTimeWithWorkingDir(workingDir, sha); ok {
1140				return &ts, []SourceRef{{
1141					BeadID:           b.ID,
1142					ClosingCommitSHA: sha,
1143					Timestamp:        &ts,
1144					Source:           "commit",
1145				}}
1146			}
1147		}
1148	
1149		if sessionID := extraString(b, "session_id", "session-id"); sessionID != "" {
1150			if sess, ok := sessionByID[sessionID]; ok {
1151				ts := sess.Timestamp.UTC()
1152				return &ts, []SourceRef{{
1153					BeadID:          b.ID,
1154					SessionID:       sess.ID,
1155					NativeSessionID: sess.NativeSessionID,
1156					NativeLogRef:    sess.NativeLogRef,
1157					Timestamp:       &ts,
1158					Source:          "session",
1159				}}
1160			}
1161		}
1162	
1163		return nil, nil
1164	}
1165	
1166	func commitTimeWithWorkingDir(workingDir, sha string) (time.Time, bool) {
1167		if sha == "" {
1168			return time.Time{}, false
1169		}
1170		cmd := exec.Command("git", "-C", workingDir, "show", "-s", "--format=%cI", sha)
1171		out, err := cmd.Output()
1172		if err != nil {
1173			return time.Time{}, false
1174		}
1175		parsed, err := time.Parse(time.RFC3339, strings.TrimSpace(string(out)))
1176		if err != nil {
1177			return time.Time{}, false
1178		}
1179		return parsed.UTC(), true
1180	}
