1320	func statusFromEvent(event bead.BeadEvent) (string, bool) {
1321		kind := normalizeToken(event.Kind)
1322		switch kind {
1323		case "open", "opened":
1324			return bead.StatusOpen, true
1325		case "in_progress", "inprogress", "started", "start", "working":
1326			return bead.StatusInProgress, true
1327		case "closed", "close", "finished", "done":
1328			return bead.StatusClosed, true
1329		case "reopened", "reopen":
1330			return bead.StatusOpen, true
1331		}
1332	
1333		candidate := normalizeToken(firstNonEmpty(event.Summary, event.Body))
1334		switch candidate {
1335		case "open", "opened":
1336			return bead.StatusOpen, true
1337		case "in_progress", "inprogress", "started", "start", "working":
1338			return bead.StatusInProgress, true
1339		case "closed", "close", "finished", "done":
1340			return bead.StatusClosed, true
1341		case "reopened", "reopen":
1342			return bead.StatusOpen, true
1343		}
1344	
1345		if strings.HasPrefix(kind, "status:") {
1346			return statusFromToken(strings.TrimPrefix(kind, "status:"))
1347		}
1348		if strings.HasPrefix(kind, "state:") {
1349			return statusFromToken(strings.TrimPrefix(kind, "state:"))
1350		}
1351		if strings.HasPrefix(kind, "transition:") {
1352			return statusFromToken(strings.TrimPrefix(kind, "transition:"))
1353		}
1354		return "", false
1355	}
