16	// Commits is the resolver for the commits field.
17	func (r *queryResolver) Commits(ctx context.Context, projectID string, first *int, after *string, last *int, before *string, since *string, author *string) (*CommitConnection, error) {
18	
19		proj, ok := r.State.GetProjectSnapshotByID(projectID)
20		if !ok {
21			return nil, fmt.Errorf("project not found: %s", projectID)
22		}
23	
24		snaps, err := gitLogCommits(proj.Path, since, author)
25		if err != nil {
26			return nil, err
27		}
28	
29		// Build full edge list with stable SHA-based cursors.
30		all := make([]*CommitEdge, len(snaps))
31		for i, c := range snaps {
32			all[i] = &CommitEdge{
33				Node:   c,
34				Cursor: encodeStableCursor(c.Sha),
35			}
36		}
37	
38		// Apply window: start after `after` cursor, end before `before` cursor.
39		startIdx := 0
40		if after != nil {
41			if afterSha, ok := decodeStableCursor(*after); ok {
42				for i, e := range all {
43					if e.Node.Sha == afterSha {
44						startIdx = i + 1
45						break
46					}
47				}
48			}
49		}
50		endIdx := len(all)
51		if before != nil {
52			if beforeSha, ok := decodeStableCursor(*before); ok {
53				for i, e := range all {
54					if e.Node.Sha == beforeSha {
55						endIdx = i
56						break
57					}
58				}
59			}
60		}
61		if startIdx > endIdx {
62			startIdx = endIdx
63		}
64	
65		windowSize := endIdx - startIdx
66		slice := all[startIdx:endIdx]
67		if first != nil && *first >= 0 && *first < len(slice) {
68			slice = slice[:*first]
69		}
70		if last != nil && *last >= 0 && *last < len(slice) {
71			slice = slice[len(slice)-*last:]
72		}
73	
74		pageInfo := &PageInfo{
75			HasPreviousPage: startIdx > 0 || (last != nil && *last >= 0 && *last < windowSize),
76			HasNextPage:     endIdx < len(all) || (first != nil && *first >= 0 && *first < windowSize),
77		}
78		if len(slice) > 0 {
79			pageInfo.StartCursor = &slice[0].Cursor
80			pageInfo.EndCursor = &slice[len(slice)-1].Cursor
81		}
82	
83		return &CommitConnection{
84			Edges:      slice,
85			PageInfo:   pageInfo,
86			TotalCount: len(all),
87		}, nil
88	}
