90	// gitLogCommits runs git log for the given project path and returns parsed commits.
91	// Up to 500 commits are fetched. Optionally filtered by since (ISO-8601) and author.
92	func gitLogCommits(path string, since, author *string) ([]*Commit, error) {
93		const sep = "\x1f"
94		const recSep = "\x1e"
95		format := "--pretty=format:%H" + sep + "%h" + sep + "%an" + sep + "%aI" + sep + "%s" + sep + "%b" + recSep
96	
97		args := []string{"-C", path, "log", format, "-n", strconv.Itoa(500)}
98		if since != nil && *since != "" {
99			args = append(args, "--since="+*since)
100		}
101		if author != nil && *author != "" {
102			args = append(args, "--author="+*author)
103		}
104	
105		cmd := exec.Command("git", args...) //nolint:gosec
106		cmd.Env = graphqlScrubbedGitEnv()
107		out, err := cmd.Output()
108		if err != nil {
109			return nil, fmt.Errorf("git log failed: %w", err)
110		}
111	
112		var commits []*Commit
113		records := strings.Split(string(out), recSep)
114		for _, rec := range records {
115			rec = strings.TrimLeft(rec, "\n")
116			if rec == "" {
117				continue
118			}
119			fields := strings.SplitN(rec, sep, 6)
120			if len(fields) < 6 {
121				continue
122			}
123			body := fields[5]
124			refs := beadRefPattern.FindAllString(fields[4]+"\n"+body, -1)
125			if refs == nil {
126				refs = []string{}
127			}
128			c := &Commit{
129				Sha:      fields[0],
130				ShortSha: fields[1],
131				Author:   fields[2],
132				Date:     fields[3],
133				Subject:  fields[4],
134				BeadRefs: refs,
135			}
136			if body != "" {
137				c.Body = &body
138			}
139			commits = append(commits, c)
140		}
141		return commits, nil
142	}
